import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common'; // 🚀 Requis pour la gestion dynamique sous Angular

@Component({
  selector: 'app-job-manage',
  standalone: true,
  imports: [CommonModule], // 🚀 Sécurité pour ne pas bloquer le rendu
  templateUrl: './job-manage.component.html',
  styleUrls: ['./job-manage.component.css']
})
export class JobManageComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  // Variables d'état
  jobsList: any[] = [];
  isLoading: boolean = true;

  ngOnInit() {
    this.fetchRecruiterJobs();
  }

  fetchRecruiterJobs() {
    // S'aligne parfaitement sur vos endpoints configurés dans Express
    const targetUrl = 'http://localhost:3000/api/recruiter/jobs/list';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: {
        'Authorization': token ? `Bearer ${token}` : ''
      }
    })
    .then(async res => {
      if (!res.ok) throw new Error("Impossible de charger les données.");
      return res.json();
    })
    .then(data => {
      // S'adapte au format de retour du backend (Tableau direct ou enveloppe .jobs)
      this.jobsList = Array.isArray(data) ? data : (data.jobs || []);
      this.isLoading = false;
      this.cdr.detectChanges(); // Notification visuelle instantanée
    })
    .catch(err => {
      console.error("Échec du chargement TunJob MySQL :", err);
      this.isLoading = false;
      this.cdr.detectChanges();
    });
  }
}
<div class="manage-container">

  <!-- 📊 BLOC DES COMPTEURS (STATISTIQUES) PLACÉ EN HAUT -->
  <div class="stats-row">
    <!-- Carte 1 : Offres Actives -->
    <div class="stat-card">
      <div class="stat-content">
        <span class="stat-label">OFFRES ACTIVES</span>
        <span class="stat-number">{{ jobsList.length }}</span>
        <span class="stat-sub green">+1 cette semaine</span>
      </div>
      <div class="stat-icon blue-bg">
        <i class="bi bi-briefcase"></i>
      </div>
    </div>

    <!-- Carte 2 : Candidatures -->
    <div class="stat-card">
      <div class="stat-content">
        <span class="stat-label">CANDIDATURES</span>
        <span class="stat-number">14</span>
        <span class="stat-sub green">+8 aujourd'hui</span>
      </div>
      <div class="stat-icon green-bg">
        <i class="bi bi-file-earmark-person"></i>
      </div>
    </div>

    <!-- Carte 3 : Entretiens -->
    <div class="stat-card">
      <div class="stat-content">
        <span class="stat-label">ENTRETIENS</span>
        <span class="stat-number">4</span>
        <span class="stat-sub gray">Planifiés ce mois</span>
      </div>
      <div class="stat-icon orange-bg">
        <i class="bi bi-calendar-event"></i>
      </div>
    </div>

    <!-- Carte 4 : Taux de Conversion -->
    <div class="stat-card">
      <div class="stat-content">
        <span class="stat-label">TAUX DE CONVERSION</span>
        <span class="stat-number">28%</span>
        <span class="stat-sub green">+-2.4% vs mois max</span>
      </div>
      <div class="stat-icon purple-bg">
        <i class="bi bi-pie-chart"></i>
      </div>
    </div>
  </div>

  <!-- 📋 TABLEAU DES ANNONCES PLACÉ EN DESSOUS -->
  <div class="manage-card">
    <div class="card-header">
      <h3><i class="bi bi-briefcase-fill"></i> Vos Annonces en Ligne</h3>
      <p>Suivez l'état de diffusion et l'attractivité de vos offres d'emploi actives.</p>
    </div>

    <div class="table-wrapper">
      <table class="jobs-table">
        <thead>
          <tr>
            <th>Intitulé du Poste</th>
            <th>Type de Contrat</th>
            <th>Localisation</th>
            <th>Candidatures Reçues</th>
            <th>Statut</th>
          </tr>
        </thead>
        <tbody>
          @if (isLoading) {
            <tr>
              <td colspan="5" style="text-align: center; padding: 25px; color: #64748b; font-weight: 500;">
                <i class="bi bi-arrow-clockwise" style="display: inline-block; animation: spin 1s linear infinite; margin-right: 8px;"></i>
                Synchronisation avec la base de données...
              </td>
            </tr>
          }

          @if (!isLoading && jobsList.length === 0) {
            <tr>
              <td colspan="5" style="text-align: center; padding: 35px; color: #64748b;">
                <i class="bi bi-folder-x" style="font-size: 26px; display: block; margin-bottom: 6px; color: #cbd5e1;"></i>
                Aucune offre publiée pour le moment.
              </td>
            </tr>
          }

          @for (job of jobsList; track job.id) {
            <tr>
              <td class="job-title">{{ job.title }}</td>
              <td>{{ job.contract_type }}</td>
              <td>{{ job.location }}</td>
              <td class="candidate-count">
                <i class="bi bi-people-fill"></i> 
                {{ job.application_count || 0 }} {{ (job.application_count || 0) <= 1 ? 'profil' : 'profils' }}
              </td>
              <td>
                <span class="status-badge" [ngClass]="job.status === 'disponible' || job.status === 'Actif' ? 'bg-green' : 'bg-gray'">
                  {{ job.status === 'disponible' ? 'Actif' : job.status }}
                </span>
              </td>
            </tr>
          }
        </tbody>
      </table>
    </div>
  </div>

</div>
